			// Check for IEnumerable types that aren't Widget lists
			if (baseType.StartsWith("IEnumerable<") || baseType.StartsWith("IList<") || baseType.StartsWith("HashSet<"))
				return true;

			// Everything else that is a reference type (class) is complex
