		/// <summary>
		/// Maps a Dart namespace to a C# namespace.
		/// </summary>
		private string MapNamespace(string dartNamespace)
		{
			if (string.IsNullOrEmpty(dartNamespace))
			{
				return "Flutter.Widgets";
			}

			// Always use Flutter as the root namespace
			// Strip source paths like "src.widgets.text" and just use "Flutter.Widgets"
			if (dartNamespace.Contains("widgets"))
			{
				return "Flutter.Widgets";
			}
			if (dartNamespace.Contains("material"))
			{
				return "Flutter.Material";
			}
			if (dartNamespace.Contains("cupertino"))
			{
				return "Flutter.Cupertino";
			}

			// Default to Flutter.Widgets
			return "Flutter.Widgets";
		}

		/// <summary>
		/// Maps a Dart base class to a C# base class.
		/// </summary>
		private string MapBaseClass(string? dartBaseClass, WidgetType widgetType)
		{
			if (!string.IsNullOrEmpty(dartBaseClass))
			{
				return dartBaseClass;
			}

			return widgetType switch
			{
				WidgetType.Stateless => "StatelessWidget",
				WidgetType.Stateful => "StatefulWidget",
				WidgetType.SingleChildRenderObject => "SingleChildRenderObjectWidget",
				WidgetType.MultiChildRenderObject => "MultiChildRenderObjectWidget",
				WidgetType.LeafRenderObject => "LeafRenderObjectWidget",
				WidgetType.Proxy => "ProxyWidget",
				_ => "Widget"
			};
		}

		/// <summary>
		/// Formats documentation comments for C# XML documentation.
		/// </summary>
		private string? FormatDocumentation(string? documentation)
		{
			if (string.IsNullOrWhiteSpace(documentation))
			{
				return null;
			}

			// Convert Dart documentation to C# XML documentation
			var lines = documentation.Split('\n');
			var formatted = new StringBuilder();

			foreach (var line in lines)
			{
				var trimmed = line.TrimStart();
				if (trimmed.StartsWith("///"))
				{
					trimmed = trimmed.Substring(3).TrimStart();
				}
				else if (trimmed.StartsWith("//"))
				{
					trimmed = trimmed.Substring(2).TrimStart();
				}

				formatted.AppendLine($"/// {trimmed}");
			}

			return formatted.ToString().TrimEnd();
		}

		/// <summary>
		/// Converts a Dart default value to C# syntax.
		/// </summary>
		private string? ConvertDartDefaultValueToCSharp(string? dartDefaultValue, string csharpType)
		{
			if (string.IsNullOrEmpty(dartDefaultValue))
			{
				return null;
			}

			// Handle type names used as default values (e.g., "EditableText" should be null)
			// These are cases where the Dart analyzer returns a type name instead of a value
			if (char.IsUpper(dartDefaultValue[0]) && !dartDefaultValue.Contains(".") && !dartDefaultValue.Contains("("))
			{
				// This looks like a bare type name (e.g., "EditableText"), convert to null
				return "null";
			}

			// Handle Dart single-quoted strings - convert to C# double-quoted strings
			// '' -> ""
			// 'text' -> "text"
			if (dartDefaultValue.StartsWith("'") && dartDefaultValue.EndsWith("'"))
			{
				var content = dartDefaultValue.Substring(1, dartDefaultValue.Length - 2);
				return $"\"{content}\"";
